  9→	"github.com/golang-jwt/jwt/v5"
 10→)
 11→
 12→// Claims extends jwt.RegisteredClaims with application-specific fields.
 13→type Claims struct {
 14→	jwt.RegisteredClaims
 15→	Email        string         `json:"email,omitempty"`
 16→	Roles        []string       `json:"roles,omitempty"`
 17→	Role         string         `json:"role,omitempty"`          // Supabase: "authenticated", "anon", etc.
 18→	TeamID       string         `json:"team_id,omitempty"`
 19→	ClientType   string         `json:"client_type,omitempty"`   // web|cli|mobile|desktop
 20→	AppMetadata  map[string]any `json:"app_metadata,omitempty"`  // Supabase: provider info
 21→	UserMetadata map[string]any `json:"user_metadata,omitempty"` // Supabase: user profile data
 22→}
 23→
 24→// NormalizedRoles returns a deduplicated union of Roles and the singular Role field.
 25→func (c *Claims) NormalizedRoles() []string {
 26→	seen := make(map[string]struct{}, len(c.Roles)+1)
 27→	var result []string
 28→	for _, r := range c.Roles {
 29→		if _, ok := seen[r]; !ok {
 30→			seen[r] = struct{}{}
 31→			result = append(result, r)
 32→		}
 33→	}
 34→	if c.Role != "" {
 35→		if _, ok := seen[c.Role]; !ok {
 36→			result = append(result, c.Role)
 37→		}
 38→	}
 39→	return result
 40→}
 41→
 42→// Provider extracts the authentication provider from AppMetadata.
 43→// Returns an empty string if the provider is not set or is not a string.
 44→func (c *Claims) Provider() string {
 45→	if c.AppMetadata == nil {
 46→		return ""
 47→	}
 48→	p, _ := c.AppMetadata["provider"].(string)
 49→	return p
 50→}
 51→
 52→// Validator validates a JWT token string and returns parsed claims.
 53→type Validator interface {
 54→	Validate(tokenString string) (*Claims, error)
 55→}
 56→
 57→// HMACValidator validates HS256 tokens using a shared secret.
 58→type HMACValidator struct {
 59→	secret     []byte
 60→	parserOpts []jwt.ParserOption
 61→}
 62→
 63→// NewHMACValidator creates a Validator using HS256 with the provided secret.
 64→// It returns an error if the secret is empty or contains only whitespace.
 65→func NewHMACValidator(secret string, opts ...jwt.ParserOption) (*HMACValidator, error) {
 66→	if strings.TrimSpace(secret) == "" {
 67→		return nil, errors.New("auth: HMAC secret must not be empty or whitespace-only")
 68→	}
 69→	return &HMACValidator{
 70→		secret:     []byte(secret),
 71→		parserOpts: opts,
 72→	}, nil
 73→}
 74→
 75→// Validate parses and validates an HS256 JWT token string.
 76→func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
 77→	claims := &Claims{}
 78→	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
 79→		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
 80→			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
 81→		}
 82→		return v.secret, nil
 83→	}, v.parserOpts...)
 84→	if err != nil {
 85→		return nil, fmt.Errorf("auth: token validation failed: %w", err)
 86→	}
 87→	if !token.Valid {
 88→		return nil, errors.New("auth: token is not valid")
 89→	}
 90→	return claims, nil
 91→}
 92→
 93→// RSAValidator validates RS256 tokens using an RSA public key.
 94→type RSAValidator struct {
 95→	publicKey  *rsa.PublicKey
 96→	parserOpts []jwt.ParserOption
 97→}
 98→
 99→// NewRSAValidator creates a Validator using RS256 with the provided PEM public key.
100→func NewRSAValidator(pemPublicKey string, opts ...jwt.ParserOption) (*RSAValidator, error) {
101→	key, err := jwt.ParseRSAPublicKeyFromPEM([]byte(pemPublicKey))
102→	if err != nil {
103→		return nil, fmt.Errorf("auth: failed to parse RSA public key: %w", err)
104→	}
105→	return &RSAValidator{
106→		publicKey:  key,
107→		parserOpts: opts,
108→	}, nil
109→}
110→
111→// Validate parses and validates an RS256 JWT token string.
112→func (v *RSAValidator) Validate(tokenString string) (*Claims, error) {
113→	claims := &Claims{}
114→	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
115→		if _, ok := t.Method.(*jwt.SigningMethodRSA); !ok {
116→			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
117→		}
118→		return v.publicKey, nil
119→	}, v.parserOpts...)
120→	if err != nil {
121→		return nil, fmt.Errorf("auth: token validation failed: %w", err)
122→	}
123→	if !token.Valid {
124→		return nil, errors.New("auth: token is not valid")
125→	}
126→	return claims, nil
127→}
