package preference

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"

	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
)

// Preferences is the typed representation of the JSONB data column.
type Preferences struct {
	HomeLatitude  *float64 `json:"homeLatitude,omitempty"`
	HomeLongitude *float64 `json:"homeLongitude,omitempty"`
	HomeState     *string  `json:"homeState,omitempty"`
}

// Service manages user preferences in the ugc schema.
type Service struct {
	pool *pgxpool.Pool
}

// NewService returns a new preference service.
func NewService(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// TeamIDForUser looks up the team_id for a given user_id.
func (s *Service) TeamIDForUser(ctx context.Context, userID string) (string, error) {
	var teamID string
	err := s.pool.QueryRow(ctx,
		`SELECT team_id FROM subscription.team_member WHERE user_id = $1`, userID,
	).Scan(&teamID)
	if err != nil {
		return "", fmt.Errorf("preference: team for user %s: %w", userID, err)
	}
	return teamID, nil
}

// Get retrieves preferences for the given team. Returns zero-value Preferences
// if no row exists.
func (s *Service) Get(ctx context.Context, teamID string) (*Preferences, error) {
	var data []byte
	err := s.pool.QueryRow(ctx,
		`SELECT data FROM ugc.preference WHERE team_id = $1`, teamID,
	).Scan(&data)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return &Preferences{}, nil
		}
		return nil, fmt.Errorf("preference: get for team %s: %w", teamID, err)
	}
	var prefs Preferences
	if err := json.Unmarshal(data, &prefs); err != nil {
		return nil, fmt.Errorf("preference: unmarshal for team %s: %w", teamID, err)
	}
	return &prefs, nil
}

// Update upserts the preferences for the given team.
func (s *Service) Update(ctx context.Context, teamID string, prefs *Preferences) (*Preferences, error) {
	data, err := json.Marshal(prefs)
	if err != nil {
		return nil, fmt.Errorf("preference: marshal: %w", err)
	}

	var result []byte
	err = s.pool.QueryRow(ctx, `
		INSERT INTO ugc.preference (team_id, data)
		VALUES ($1, $2)
		ON CONFLICT (team_id) DO UPDATE
			SET data = $2, updated = CURRENT_TIMESTAMP
		RETURNING data`,
		teamID, data,
	).Scan(&result)
	if err != nil {
		return nil, fmt.Errorf("preference: update for team %s: %w", teamID, err)
	}

	var updated Preferences
	if err := json.Unmarshal(result, &updated); err != nil {
		return nil, fmt.Errorf("preference: unmarshal result for team %s: %w", teamID, err)
	}
	return &updated, nil
}

package resolver

// This file will not be regenerated automatically.
//
// It serves as dependency injection for your app, add any dependencies you require here.

import (
	"regexp"

	"github.com/ketang/kapow/api/internal/db"
	"github.com/ketang/kapow/api/internal/preference"
	"github.com/ketang/kapow/api/internal/search"
)

var zipRegexp = regexp.MustCompile(`^\d{5}$`)

// Resolver is the root resolver, holding injected application dependencies.
type Resolver struct {
	DB         db.Querier
	Search     *search.Registry
	Preference *preference.Service
}

package router

import (
	"io/fs"
	"log/slog"
	"net"
	"net/http"
	"sync/atomic"
	"time"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/99designs/gqlgen/graphql/playground"
	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/httprate"
	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/ketang/kapow/api/graph/generated"
	"github.com/ketang/kapow/api/graph/resolver"
	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/config"
	kapowhandler "github.com/ketang/kapow/api/internal/handler"
	kapowmcp "github.com/ketang/kapow/api/internal/mcp"
	kapowmiddleware "github.com/ketang/kapow/api/internal/middleware"
	kapowotel "github.com/ketang/kapow/api/internal/otel"
	"github.com/ketang/kapow/api/internal/preference"
	"github.com/ketang/kapow/api/internal/search"
	"github.com/ketang/kapow/api/internal/user"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config            *config.Config
	DB                *pgxpool.Pool
	Validator         auth.Validator
	Search            *search.Registry
	UserService       *user.Service
	PreferenceService *preference.Service

	// HTTPDetailConfig holds the hot-reloadable HTTP debug logging config.
	// A future admin endpoint can call .Store() to change settings at runtime.
	// If nil, New() initialises it from Config.
	HTTPDetailConfig *atomic.Pointer[kapowmiddleware.HTTPDetailConfig]

	// PrivateCIDRs restricts /private/* routes to these IP ranges.
	PrivateCIDRs []*net.IPNet

	// UI holds the embedded SPA filesystem. When non-nil, unmatched routes
	// serve the SPA (static files + index.html fallback).
	UI fs.FS
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Initialise hot-reloadable HTTP detail config if not provided.
	if deps.HTTPDetailConfig == nil {
		deps.HTTPDetailConfig = &atomic.Pointer[kapowmiddleware.HTTPDetailConfig]{}
		deps.HTTPDetailConfig.Store(kapowmiddleware.NewHTTPDetailConfig(deps.Config))
	}

	// Global middleware (applied to every request)
	if deps.Config.OTelEnabled {
		r.Use(kapowotel.Middleware("kapow-api"))
	}
	r.Use(kapowmiddleware.RequestID)
	r.Use(kapowmiddleware.Logging)
	r.Use(kapowmiddleware.Recovery)
	r.Use(kapowmiddleware.HTTPDetail(deps.HTTPDetailConfig))
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// Build gqlgen server
	gqlSrv := handler.New(generated.NewExecutableSchema(generated.Config{
		Resolvers: &resolver.Resolver{DB: deps.DB, Search: deps.Search, Preference: deps.PreferenceService},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	if deps.Config.GraphQLIntrospection {
		gqlSrv.Use(extension.Introspection{})
	}

	// GraphQL endpoint — optional auth (anonymous allowed, user provisioned if token present)
	r.Route("/graphql", func(r chi.Router) {
		r.Use(kapowmiddleware.OptionalAuth(deps.Validator))
		r.Use(kapowmiddleware.EnsureUser(deps.UserService))
		if deps.Config.RateLimitEnabled {
			r.Use(authRateLimitOverride(deps.Config.RateLimitGraphQLAuth))
			r.Use(httprate.Limit(
				deps.Config.RateLimitGraphQL,
				time.Minute,
				httprate.WithKeyFuncs(authOrIPKeyFunc),
			))
		}
		r.Post("/", gqlSrv.ServeHTTP)
		r.Get("/", gqlSrv.ServeHTTP)
	})

	// Dev-only mock auth endpoint — issues JWTs without Supabase
	if deps.Config.Env == "development" {
		r.Post("/dev/auth/login", kapowhandler.DevLogin(deps.Config.JWTSecret))
		slog.Info("router: dev auth endpoint enabled at /dev/auth/login")
	}

	// GraphQL Playground (dev only)
	if deps.Config.GraphQLPlayground {
		r.Get("/playground", playground.Handler("Kapow API", "/graphql"))
		slog.Info("router: GraphQL Playground enabled at /playground")
	}

	// CSV export endpoint — optional auth + rate limited
	r.Route("/api/export", func(r chi.Router) {
		r.Use(kapowmiddleware.OptionalAuth(deps.Validator))
		r.Use(kapowmiddleware.EnsureUser(deps.UserService))
		if deps.Config.RateLimitEnabled {
			r.Use(httprate.Limit(
				deps.Config.RateLimitExport,
				time.Minute,
				httprate.WithKeyFuncs(authOrIPKeyFunc),
			))
		}
		r.Get("/csv", kapowhandler.ExportCSV(deps.DB, deps.Search, deps.Config.MaxExportRows))
	})

	// Private (internal) routes — IP allowlisted
	r.Route("/private", func(r chi.Router) {
		if len(deps.PrivateCIDRs) > 0 {
			r.Use(kapowmiddleware.IPAllowlist(deps.PrivateCIDRs))
		}
		r.Get("/healthcheck", kapowhandler.Health(deps.DB))
		r.Get("/log-config", kapowhandler.LogConfig(deps.Config))
		r.Put("/log-config", kapowhandler.LogConfig(deps.Config))
	})

	// MCP (Model Context Protocol) endpoint — AI client integration
	// Protected with mandatory Auth middleware; unauthenticated requests
	// receive 401 with WWW-Authenticate header per MCP OAuth 2.1 spec.
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(kapowmiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				r.Use(httprate.Limit(
					deps.Config.RateLimitMCP,
					time.Minute,
					httprate.WithKeyFuncs(authOrIPKeyFunc),
				))
			}
			r.Handle("/*", kapowmcp.NewHandler(deps.DB, deps.Search))
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// OAuth 2.1 Protected Resource Metadata (RFC 9728)
	r.Get("/.well-known/oauth-protected-resource", kapowhandler.ProtectedResourceMetadata(deps.Config))

	// Embedded SPA — serve static files and fall back to index.html
	if deps.UI != nil {
		r.NotFound(kapowhandler.SPAHandler(deps.UI).ServeHTTP)
		slog.Info("router: embedded SPA enabled")
	}

	slog.Info("router: initialized",
		"graphql_introspection", deps.Config.GraphQLIntrospection,
		"graphql_playground", deps.Config.GraphQLPlayground,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
		"embedded_ui", deps.UI != nil,
	)

	return r
}

// authOrIPKeyFunc keys by user subject if authenticated, otherwise by client IP.
func authOrIPKeyFunc(r *http.Request) (string, error) {
	if claims := auth.GetClaims(r.Context()); claims != nil {
		return "user:" + claims.Subject, nil
	}
	return "ip:" + r.RemoteAddr, nil
}

// authRateLimitOverride returns middleware that raises the httprate request limit
// for authenticated users by setting WithRequestLimit in the request context.
func authRateLimitOverride(authLimit int) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			if auth.GetClaims(r.Context()) != nil {
				r = r.WithContext(httprate.WithRequestLimit(r.Context(), authLimit))
			}
			next.ServeHTTP(w, r)
		})
	}
}

package config

import (
	"fmt"
	"log/slog"
	"strings"
	"time"

	"github.com/caarlos0/env/v11"
)

// Config holds all application configuration loaded from environment variables.
type Config struct {
	Host string `env:"HOST" envDefault:"0.0.0.0"`
	Port int    `env:"PORT" envDefault:"8081"`

	DatabaseURL string `env:"DATABASE_URL,required"`

	JWTSecret    string `env:"JWT_SECRET"` //nolint:gosec // G117: config field name, not a hardcoded secret
	JWTPublicKey string `env:"JWT_PUBLIC_KEY"`
	JWTIssuer    string `env:"JWT_ISSUER"`
	JWTAudience  string `env:"JWT_AUDIENCE"`

	OIDCDiscoveryURL string `env:"OIDC_DISCOVERY_URL"`

	LogLevel  string `env:"LOG_LEVEL" envDefault:"info"`
	LogFormat string `env:"LOG_FORMAT" envDefault:"json"`

	Env string `env:"ENV" envDefault:"development"`

	CORSOrigins string `env:"CORS_ORIGINS"`

	GraphQLPlayground    bool `env:"GRAPHQL_PLAYGROUND" envDefault:"false"`
	GraphQLIntrospection bool `env:"GRAPHQL_INTROSPECTION" envDefault:"true"`

	MCPEnabled  bool `env:"MCP_ENABLED" envDefault:"true"`
	OTelEnabled bool `env:"OTEL_ENABLED" envDefault:"false"`

	ShutdownTimeout time.Duration `env:"SHUTDOWN_TIMEOUT" envDefault:"15s"`

	MaxExportRows int `env:"MAX_EXPORT_ROWS" envDefault:"500"`

	// Rate limiting
	RateLimitEnabled     bool   `env:"RATE_LIMIT_ENABLED" envDefault:"true"`
	RateLimitGraphQL     int    `env:"RATE_LIMIT_GRAPHQL" envDefault:"60"`
	RateLimitGraphQLAuth int    `env:"RATE_LIMIT_GRAPHQL_AUTH" envDefault:"120"`
	RateLimitExport      int    `env:"RATE_LIMIT_EXPORT" envDefault:"10"`
	RateLimitMCP         int    `env:"RATE_LIMIT_MCP" envDefault:"120"`
	PrivateAllowlistCIDRs string `env:"PRIVATE_ALLOWLIST_CIDRS" envDefault:"127.0.0.0/8,::1/128"`

	// HTTP debug logging
	HTTPDebugRequestHeaders  string `env:"HTTP_DEBUG_REQUEST_HEADERS" envDefault:"none"`
	HTTPDebugSelectedHeaders string `env:"HTTP_DEBUG_SELECTED_HEADERS" envDefault:"Content-Type,Accept,User-Agent"`
	HTTPDebugRedactSensitive bool   `env:"HTTP_DEBUG_REDACT_SENSITIVE" envDefault:"true"`
	HTTPDebugResponseMode    string `env:"HTTP_DEBUG_RESPONSE_MODE" envDefault:"none"`
	HTTPDebugBodyMaxBytes    int    `env:"HTTP_DEBUG_BODY_MAX_BYTES" envDefault:"4096"`

	// logLevelVar holds the dynamic log level. It is initialized by LogHandler
	// and can be updated at runtime to change the global log level without a restart.
	logLevelVar slog.LevelVar

	// swappableWriter is the log output target, swappable at runtime.
	swappableWriter *SwappableWriter

	// categoryHandler wraps the slog handler with per-category level overrides.
	categoryHandler *CategoryHandler
}

// Load parses and validates configuration from environment variables.
func Load() (*Config, error) {
	cfg := &Config{}
	if err := env.Parse(cfg); err != nil {
		return nil, fmt.Errorf("config: %w", err)
	}
	return cfg, nil
}

// Addr returns the host:port bind address.
func (c *Config) Addr() string {
	return fmt.Sprintf("%s:%d", c.Host, c.Port)
}

// LevelTrace is a custom log level below DEBUG for very detailed diagnostic
// output. Usage: logger.Log(ctx, config.LevelTrace, "msg", "key", val)
const LevelTrace = slog.Level(-8)

// ParseLogLevel converts a log level string to the corresponding slog.Level.
func ParseLogLevel(s string) slog.Level {
	switch s {
	case "trace":
		return LevelTrace
	case "debug":
		return slog.LevelDebug
	case "warn":
		return slog.LevelWarn
	case "error":
		return slog.LevelError
	default:
		return slog.LevelInfo
	}
}

// LogHandler returns an slog.Handler configured per LOG_LEVEL and LOG_FORMAT.
// The handler uses a dynamic LevelVar so the log level can be changed at
// runtime via LogLevelVar().Set() without recreating the handler. Output is
// routed through a SwappableWriter and wrapped with a CategoryHandler for
// per-category level overrides.
func (c *Config) LogHandler() slog.Handler {
	c.logLevelVar.Set(ParseLogLevel(c.LogLevel))
	c.swappableWriter = NewSwappableWriter()

	opts := &slog.HandlerOptions{
		Level:     &c.logLevelVar,
		AddSource: c.Env == "development",
		ReplaceAttr: func(groups []string, a slog.Attr) slog.Attr {
			if a.Key == slog.LevelKey {
				if level, ok := a.Value.Any().(slog.Level); ok && level == LevelTrace {
					a.Value = slog.StringValue("TRACE")
				}
			}
			return a
		},
	}

	var inner slog.Handler
	if c.LogFormat == "text" {
		inner = slog.NewTextHandler(c.swappableWriter, opts)
	} else {
		inner = slog.NewJSONHandler(c.swappableWriter, opts)
	}

	c.categoryHandler = NewCategoryHandler(inner, &c.logLevelVar)
	return c.categoryHandler
}

// LogLevelVar returns the dynamic log level variable. Callers can change
// the active log level at runtime by calling Set() on the returned LevelVar.
func (c *Config) LogLevelVar() *slog.LevelVar {
	return &c.logLevelVar
}

// LogWriter returns the swappable writer used for log output.
// Returns nil if LogHandler has not been called yet.
func (c *Config) LogWriter() *SwappableWriter {
	return c.swappableWriter
}

// LogCategoryHandler returns the category handler for per-category level overrides.
// Returns nil if LogHandler has not been called yet.
func (c *Config) LogCategoryHandler() *CategoryHandler {
	return c.categoryHandler
}

// HTTPDebugEnabled reports whether any HTTP debug logging is configured.
func (c *Config) HTTPDebugEnabled() bool {
	return c.HTTPDebugRequestHeaders != "none" || c.HTTPDebugResponseMode != "none"
}

// ParsedSelectedHeaders splits the comma-separated HTTPDebugSelectedHeaders
// into a trimmed slice of header names.
func (c *Config) ParsedSelectedHeaders() []string {
	raw := strings.Split(c.HTTPDebugSelectedHeaders, ",")
	out := make([]string, 0, len(raw))
	for _, h := range raw {
		h = strings.TrimSpace(h)
		if h != "" {
			out = append(out, h)
		}
	}
	return out
}

type Preferences {
