import { useState, useEffect, useCallback } from 'react'
import { Modal, Stack, Select, Alert, Group, Text } from '@mantine/core'
import { Button } from '@/components/ui/button'
import { LocationInput, type UserLocationValue } from '@/components/search/LocationInput'
import { US_STATES } from '@/components/search/constants'
import { usePreferencesStore } from '@/stores/preferencesStore'
import { MapPin } from 'lucide-react'

interface PreferencesModalProps {
  opened: boolean
  onClose: () => void
}

type FeedbackState = { type: 'success' | 'error'; message: string } | null

export function PreferencesModal({ opened, onClose }: PreferencesModalProps) {
  const homeLatitude = usePreferencesStore((s) => s.homeLatitude)
  const homeLongitude = usePreferencesStore((s) => s.homeLongitude)
  const homeState = usePreferencesStore((s) => s.homeState)
  const loaded = usePreferencesStore((s) => s.loaded)
  const load = usePreferencesStore((s) => s.load)
  const update = usePreferencesStore((s) => s.update)

  const [location, setLocation] = useState<UserLocationValue | undefined>(undefined)
  const [state, setState] = useState<string | null>(null)
  const [saving, setSaving] = useState(false)
  const [feedback, setFeedback] = useState<FeedbackState>(null)

  // Load preferences when modal opens
  useEffect(() => {
    if (opened) {
      void load()
    }
  }, [opened, load])

  // Sync store values into local state when loaded
  useEffect(() => {
    if (!loaded) return
    if (homeLatitude != null && homeLongitude != null) {
      setLocation({
        latitude: homeLatitude,
        longitude: homeLongitude,
        state: homeState ?? undefined,
      })
    } else {
      setLocation(undefined)
    }
    setState(homeState)
  }, [loaded, homeLatitude, homeLongitude, homeState])

  // Clear feedback when modal closes
  useEffect(() => {
    if (!opened) setFeedback(null)
  }, [opened])

  const handleSave = useCallback(async () => {
    setSaving(true)
    setFeedback(null)
    try {
      await update({
        homeLatitude: location?.latitude ?? null,
        homeLongitude: location?.longitude ?? null,
        homeState: state ?? location?.state ?? null,
      })
      setFeedback({ type: 'success', message: 'Preferences saved.' })
    } catch {
      setFeedback({ type: 'error', message: 'Failed to save preferences.' })
    } finally {
      setSaving(false)
    }
  }, [location, state, update])

  const handleClear = useCallback(async () => {
    setSaving(true)
    setFeedback(null)
    try {
      await update({
        homeLatitude: null,
        homeLongitude: null,
        homeState: null,
      })
      setLocation(undefined)
      setState(null)
      setFeedback({ type: 'success', message: 'Preferences cleared.' })
    } catch {
      setFeedback({ type: 'error', message: 'Failed to clear preferences.' })
    } finally {
      setSaving(false)
    }
  }, [update])

  const handleLocationChange = useCallback((loc: UserLocationValue | undefined) => {
    setLocation(loc)
    // Auto-set state from location if available and state not manually set
    if (loc?.state && !state) {
      setState(loc.state)
    }
    setFeedback(null)
  }, [state])

  const hasPreferences = location != null || state != null

  return (
    <Modal opened={opened} onClose={onClose} title="Preferences" size="sm">
      <Stack gap="md">
        <Stack gap="xs">
          <Text size="sm" fw={500}>
            Home location
          </Text>
          <LocationInput value={location} onChange={handleLocationChange} />
        </Stack>

        <Select
          label="Home state"
          placeholder="Select a state"
          data={US_STATES}
          value={state}
          onChange={setState}
          searchable
          clearable
        />

        {feedback && (
          <Alert
            color={feedback.type === 'success' ? 'green' : 'red'}
            variant="light"
          >
            {feedback.message}
          </Alert>
        )}

        <Group justify="space-between">
          <Button
            variant="light"
            size="xs"
            onClick={() => void handleClear()}
            disabled={saving || !hasPreferences}
          >
            Clear all
          </Button>
          <Group gap="xs">
            <Button variant="outline" size="xs" onClick={onClose}>
              Cancel
            </Button>
            <Button
              variant="accent"
              size="xs"
              onClick={() => void handleSave()}
              disabled={saving}
              leftSection={<MapPin size={14} />}
            >
              {saving ? 'Saving...' : 'Save'}
            </Button>
          </Group>
        </Group>
      </Stack>
    </Modal>
  )
}

