  opened: boolean
  onClose: () => void
}

const CATEGORY_OPTIONS = [
  { value: 'BUG', label: 'Bug Report' },
  { value: 'FEATURE', label: 'Feature Request' },
  { value: 'GENERAL', label: 'General Feedback' },
]

const SubmitFeedbackMutation = graphql(`
  mutation SubmitFeedback($input: SubmitFeedbackInput!) {
    submitFeedback(input: $input) {
      id
      success
    }
  }
`)

type FeedbackState = { type: 'success' | 'error'; message: string } | null

export function FeedbackModal({ opened, onClose }: FeedbackModalProps) {
  const session = useAuthStore((s) => s.session)

  const [category, setCategory] = useState<string | null>(null)
  const [subject, setSubject] = useState('')
  const [description, setDescription] = useState('')
  const [email, setEmail] = useState('')
  const [submitting, setSubmitting] = useState(false)
  const [feedback, setFeedback] = useState<FeedbackState>(null)
  const [errors, setErrors] = useState<Record<string, string>>({})

  const [, executeMutation] = useMutation(SubmitFeedbackMutation)

  const resetForm = useCallback(() => {
    setCategory(null)
    setSubject('')
    setDescription('')
    setEmail('')
    setFeedback(null)
    setErrors({})
  }, [])

  const validate = useCallback((): boolean => {
    const newErrors: Record<string, string> = {}
    if (!category) newErrors.category = 'Category is required'
    if (!subject.trim()) newErrors.subject = 'Subject is required'
    if (!description.trim()) newErrors.description = 'Description is required'
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }, [category, subject, description])

  const handleSubmit = useCallback(async () => {
    if (!validate()) return

    setSubmitting(true)
    setFeedback(null)

    const result = await executeMutation({
      input: {
        category: category!,
        subject: subject.trim(),
        description: description.trim(),
        email: session ? undefined : email.trim() || undefined,
        userAgent: navigator.userAgent,
        pageUrl: window.location.href,
      },
    })

    setSubmitting(false)

    if (result.error) {
      setFeedback({ type: 'error', message: 'Failed to send feedback. Please try again.' })
      return
    }

    setFeedback({ type: 'success', message: 'Thank you! Your feedback has been submitted.' })
    setTimeout(() => {
      resetForm()
      onClose()
    }, 1500)
  }, [validate, executeMutation, category, subject, description, session, email, resetForm, onClose])

  const handleClose = useCallback(() => {
    resetForm()
    onClose()
  }, [resetForm, onClose])

  return (
    <Modal opened={opened} onClose={handleClose} title="Send Feedback" size="md">
      <Stack gap="md">
        <Select
          label="Category"
          placeholder="What kind of feedback?"
          required
          data={CATEGORY_OPTIONS}
          value={category}
          onChange={setCategory}
          error={errors.category}
        />

        <TextInput
          label="Subject"
          placeholder="Brief summary"
          required
          maxLength={200}
          value={subject}
          onChange={(e) => setSubject(e.currentTarget.value)}
          error={errors.subject}
        />

        <Textarea
          label="Description"
          placeholder="Tell us more..."
          required
          maxLength={5000}
          minRows={4}
          value={description}
          onChange={(e) => setDescription(e.currentTarget.value)}
          error={errors.description}
        />

        {!session && (
          <TextInput
            label="Email"
            placeholder="your@email.com"
            description="Optional — so we can follow up"
            value={email}
            onChange={(e) => setEmail(e.currentTarget.value)}
          />
        )}

        {feedback && (
          <Alert color={feedback.type === 'success' ? 'green' : 'red'} variant="light">
            {feedback.message}
          </Alert>
        )}

        <Group justify="flex-end">
          <Button variant="outline" onClick={handleClose}>
            Cancel
          </Button>
          <Button
            variant="accent"
            onClick={() => void handleSubmit()}
            disabled={submitting}
          >
            {submitting ? 'Sending...' : 'Send Feedback'}
          </Button>
        </Group>
      </Stack>
    </Modal>
  )
}

package feedback

import (
	"context"
	"crypto/rand"
	"encoding/json"
	"fmt"

	"github.com/jackc/pgx/v5/pgxpool"
)

// SubmitInput holds the data for a feedback submission.
type SubmitInput struct {
	Category    string
	Subject     string
	Description string
	Email       string // optional, for anonymous users
	UserAgent   string // optional
	PageURL     string // optional
	UserID      string // from JWT if authenticated
	UserEmail   string // from JWT if authenticated
}

// Service manages user feedback submissions.
type Service struct {
	pool *pgxpool.Pool
}

// NewService returns a new feedback service.
func NewService(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// validate checks that the required fields are present and within size limits.
func validate(input SubmitInput) error {
	if input.Subject == "" {
		return fmt.Errorf("feedback: subject is required")
	}
	if len(input.Subject) > 200 {
		return fmt.Errorf("feedback: subject exceeds 200 characters")
	}
	if input.Description == "" {
		return fmt.Errorf("feedback: description is required")
	}
	if len(input.Description) > 5000 {
		return fmt.Errorf("feedback: description exceeds 5000 characters")
	}
	return nil
}

// Submit validates and persists a feedback submission. Returns the generated ID.
func (s *Service) Submit(ctx context.Context, input SubmitInput) (string, error) {
	if err := validate(input); err != nil {
		return "", err
	}

	id, err := newUUID()
	if err != nil {
		return "", fmt.Errorf("feedback: generate id: %w", err)
	}

	data := map[string]string{
		"category":    input.Category,
		"subject":     input.Subject,
		"description": input.Description,
	}
	if input.UserAgent != "" {
		data["userAgent"] = input.UserAgent
	}
	if input.PageURL != "" {
		data["pageUrl"] = input.PageURL
	}

	dataJSON, err := json.Marshal(data)
	if err != nil {
		return "", fmt.Errorf("feedback: marshal data: %w", err)
	}

	// Determine user email: prefer JWT email, fall back to input email.
	email := input.UserEmail
	if email == "" {
		email = input.Email
	}

	// Use nil for empty optional strings so the DB stores NULL.
	var userID *string
	if input.UserID != "" {
		userID = &input.UserID
	}
	var userEmail *string
	if email != "" {
		userEmail = &email
	}

	var returnedID string
	err = s.pool.QueryRow(ctx,
		`INSERT INTO internal.user_feedback (id, user_id, user_email, data)
		 VALUES ($1, $2, $3, $4)
		 RETURNING id`,
		id, userID, userEmail, dataJSON,
	).Scan(&returnedID)
	if err != nil {
		return "", fmt.Errorf("feedback: insert: %w", err)
	}

	return returnedID, nil
}

// newUUID generates a UUID v4 string using crypto/rand.
func newUUID() (string, error) {
	var b [16]byte
	if _, err := rand.Read(b[:]); err != nil {
		return "", err
	}
	// Set version 4 and variant bits per RFC 4122.
	b[6] = (b[6] & 0x0f) | 0x40
	b[8] = (b[8] & 0x3f) | 0x80
	return fmt.Sprintf("%08x-%04x-%04x-%04x-%012x",
		b[0:4], b[4:6], b[6:8], b[8:10], b[10:16]), nil
}

