package feedback

import (
	"strings"
	"testing"
)

func TestValidate_EmptySubject(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     "",
		Description: "some description",
	})
	if err == nil {
		t.Fatal("expected error for empty subject")
	}
	if !strings.Contains(err.Error(), "subject is required") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestValidate_SubjectTooLong(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     strings.Repeat("a", 201),
		Description: "some description",
	})
	if err == nil {
		t.Fatal("expected error for long subject")
	}
	if !strings.Contains(err.Error(), "subject exceeds 200 characters") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestValidate_EmptyDescription(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     "test subject",
		Description: "",
	})
	if err == nil {
		t.Fatal("expected error for empty description")
	}
	if !strings.Contains(err.Error(), "description is required") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestValidate_DescriptionTooLong(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     "test subject",
		Description: strings.Repeat("a", 5001),
	})
	if err == nil {
		t.Fatal("expected error for long description")
	}
	if !strings.Contains(err.Error(), "description exceeds 5000 characters") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestValidate_ValidInput(t *testing.T) {
	err := validate(SubmitInput{
		Subject:     "Bug report",
		Description: "Something is broken.",
		Category:    "BUG",
	})
	if err != nil {
		t.Fatalf("expected no error, got: %v", err)
	}
}

func TestValidate_MaxLengthBoundary(t *testing.T) {
	// Exactly at the limit should pass.
	err := validate(SubmitInput{
		Subject:     strings.Repeat("a", 200),
		Description: strings.Repeat("b", 5000),
	})
	if err != nil {
		t.Fatalf("expected no error at boundary, got: %v", err)
	}
}

func TestNewUUID(t *testing.T) {
	id, err := newUUID()
	if err != nil {
		t.Fatalf("newUUID failed: %v", err)
	}
	if len(id) != 36 {
		t.Fatalf("expected 36-char UUID, got %d chars: %s", len(id), id)
	}
	// Check version nibble is 4.
	if id[14] != '4' {
		t.Fatalf("expected version 4, got %c at position 14", id[14])
	}

	// Ensure uniqueness.
	id2, err := newUUID()
	if err != nil {
		t.Fatalf("second newUUID failed: %v", err)
	}
	if id == id2 {
		t.Fatal("two UUIDs should not be equal")
	}
}

