	"github.com/ketang/kapow/api/internal/feedback"
)

// SubmitFeedback is the resolver for the submitFeedback field.
func (r *mutationResolver) SubmitFeedback(ctx context.Context, input model.SubmitFeedbackInput) (*model.FeedbackResult, error) {
	claims := auth.GetClaims(ctx)

	if claims == nil && !r.Config.FeedbackAnonymousEnabled {
		return nil, fmt.Errorf("submitFeedback: authentication required (anonymous feedback is disabled)")
	}

	fi := feedback.SubmitInput{
		Category:    string(input.Category),
		Subject:     input.Subject,
		Description: input.Description,
	}

	if input.Email != nil {
		fi.Email = *input.Email
	}
	if input.UserAgent != nil {
		fi.UserAgent = *input.UserAgent
	}
	if input.PageURL != nil {
		fi.PageURL = *input.PageURL
	}

	if claims != nil {
		fi.UserID = claims.Subject
		fi.UserEmail = claims.Email
	}

	id, err := r.Feedback.Submit(ctx, fi)
	if err != nil {
		return nil, fmt.Errorf("submitFeedback: %w", err)
	}

	return &model.FeedbackResult{
		ID:      id,
		Success: true,
	}, nil
}

