package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"strings"
	"time"

	"github.com/google/go-github/v69/github"
	"github.com/jackc/pgx/v5/pgxpool"
)

type feedbackRow struct {
	ID        string
	Created   time.Time
	UserID    *string
	UserEmail *string
	Data      json.RawMessage
}

type feedbackData struct {
	Category    string `json:"category"`
	Subject     string `json:"subject"`
	Description string `json:"description"`
	UserAgent   string `json:"userAgent,omitempty"`
	PageURL     string `json:"pageUrl,omitempty"`
}

// EnsureLabels creates the feedback labels in the GitHub repo if they don't
// already exist. A 422 response (already exists) is silently ignored.
func EnsureLabels(ctx context.Context, client *github.Client, owner, repo string) error {
	labels := []struct {
		Name  string
		Color string
	}{
		{"feedback:bug", "d73a4a"},
		{"feedback:feature", "a2eeef"},
		{"feedback:general", "cfd3d7"},
	}

	for _, l := range labels {
		_, resp, err := client.Issues.CreateLabel(ctx, owner, repo, &github.Label{
			Name:  github.Ptr(l.Name),
			Color: github.Ptr(l.Color),
		})
		if err != nil {
			if resp != nil && resp.StatusCode == http.StatusUnprocessableEntity {
				slog.Debug("feedbacksync: label already exists", "label", l.Name)
				continue
			}
			return fmt.Errorf("feedbacksync: create label %q: %w", l.Name, err)
		}
		slog.Info("feedbacksync: created label", "label", l.Name)
	}
	return nil
}

// FetchUnsynced returns up to limit feedback rows that have not yet been
// synced to GitHub (github_issue_url IS NULL).
func FetchUnsynced(ctx context.Context, pool *pgxpool.Pool, limit int) ([]feedbackRow, error) {
	rows, err := pool.Query(ctx, `
		SELECT id, created, user_id, user_email, data
		FROM internal.user_feedback
		WHERE github_issue_url IS NULL
		ORDER BY created
		LIMIT $1
	`, limit)
	if err != nil {
		return nil, fmt.Errorf("feedbacksync: query unsynced feedback: %w", err)
	}
	defer rows.Close()

	var result []feedbackRow
	for rows.Next() {
		var r feedbackRow
		if err := rows.Scan(&r.ID, &r.Created, &r.UserID, &r.UserEmail, &r.Data); err != nil {
			return nil, fmt.Errorf("feedbacksync: scan feedback row: %w", err)
		}
		result = append(result, r)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("feedbacksync: iterate feedback rows: %w", err)
	}
	return result, nil
}

// CategoryToLabel maps a feedback category to a GitHub label name.
func CategoryToLabel(category string) string {
	switch strings.ToUpper(category) {
	case "BUG":
		return "feedback:bug"
	case "FEATURE":
		return "feedback:feature"
	default:
		return "feedback:general"
	}
}

// BuildIssue constructs a GitHub IssueRequest from a feedback database row.
func BuildIssue(row feedbackRow) (*github.IssueRequest, error) {
	var data feedbackData
	if err := json.Unmarshal(row.Data, &data); err != nil {
		return nil, fmt.Errorf("feedbacksync: parse feedback data for %s: %w", row.ID, err)
	}

	subject := data.Subject
	if len(subject) > 240 {
		subject = subject[:240]
	}
	title := fmt.Sprintf("[Feedback] %s", subject)

	email := "Anonymous"
	if row.UserEmail != nil && *row.UserEmail != "" {
		email = *row.UserEmail
	}
	pageURL := "N/A"
	if data.PageURL != "" {
		pageURL = data.PageURL
	}
	userAgent := "N/A"
	if data.UserAgent != "" {
		userAgent = data.UserAgent
	}

	body := fmt.Sprintf(`## Description

%s

---

**Category:** %s
**Submitted:** %s
**Page:** %s
**Email:** %s
**User Agent:** %s

---
*Submitted via Kapow feedback form · Record ID: %s*`,
		data.Description,
		data.Category,
		row.Created.Format(time.RFC3339),
		pageURL,
		email,
		userAgent,
		row.ID,
	)

	label := CategoryToLabel(data.Category)

	return &github.IssueRequest{
		Title:  github.Ptr(title),
		Body:   github.Ptr(body),
		Labels: &[]string{label},
	}, nil
}

// MarkSynced updates the feedback row with the URL of the created GitHub issue.
func MarkSynced(ctx context.Context, pool *pgxpool.Pool, feedbackID, issueURL string) error {
	_, err := pool.Exec(ctx, `
		UPDATE internal.user_feedback SET github_issue_url = $1 WHERE id = $2
	`, issueURL, feedbackID)
	if err != nil {
		return fmt.Errorf("feedbacksync: mark synced %s: %w", feedbackID, err)
	}
	return nil
}

// Sync fetches unsynced feedback from the database, creates GitHub issues,
// and marks each row as synced. In dry-run mode, no GitHub API calls are made
// and no database updates occur.
func Sync(ctx context.Context, pool *pgxpool.Pool, client *github.Client, owner, repo string, dryRun bool, batchSize int) error {
	if !dryRun {
		if err := EnsureLabels(ctx, client, owner, repo); err != nil {
			return err
		}
	}

	rows, err := FetchUnsynced(ctx, pool, batchSize)
	if err != nil {
		return err
	}

	if len(rows) == 0 {
		slog.Info("feedbacksync: no unsynced feedback found")
		return nil
	}

	slog.Info("feedbacksync: found unsynced feedback", "count", len(rows))

	var (
		created  int
		firstErr error
	)

	for _, row := range rows {
		issueReq, err := BuildIssue(row)
		if err != nil {
			slog.Error("feedbacksync: skipping row", "id", row.ID, "error", err)
			if firstErr == nil {
				firstErr = err
			}
			continue
		}

		if dryRun {
			slog.Info("feedbacksync: dry-run would create issue",
				"id", row.ID,
				"title", *issueReq.Title,
				"labels", *issueReq.Labels,
			)
			created++
			continue
		}

		issue, _, err := client.Issues.Create(ctx, owner, repo, issueReq)
		if err != nil {
			slog.Error("feedbacksync: failed to create issue", "id", row.ID, "error", err)
			if firstErr == nil {
				firstErr = fmt.Errorf("feedbacksync: create issue for %s: %w", row.ID, err)
			}
			continue
		}

		if err := MarkSynced(ctx, pool, row.ID, issue.GetHTMLURL()); err != nil {
			slog.Error("feedbacksync: failed to mark synced", "id", row.ID, "error", err)
			if firstErr == nil {
				firstErr = err
			}
			continue
		}

		slog.Info("feedbacksync: created issue",
			"id", row.ID,
			"issue", issue.GetHTMLURL(),
		)
		created++
	}

	slog.Info("feedbacksync: sync complete", "created", created, "total", len(rows))
	return firstErr
}
